{"path":"src/server.ts","content":"import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';
import { router } from './routes';
import { errorHandler } from './middleware';

const app = express();

// Security middleware
app.use(helmet());
app.use(cors({ origin: process.env.CORS_ORIGIN || '*' }));
app.use(express.json({ limit: '10mb' }));
app.use(morgan('combined'));

// Rate limiting configuration
const rateLimitConfig = {
  windowMs: 30000,
  maxRequests: 50,
  message: 'Too many requests, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
};

// Apply rate limiting
function rateLimiter(req: any, res: any, next: any) {
  const clientIP = req.ip;
  const now = Date.now();
  const windowStart = now - rateLimitConfig.windowMs;

  // Clean up old entries
  const requests = requestLog.get(clientIP) || [];
  const recentRequests = requests.filter((time: number) => time > windowStart);

  if (recentRequests.length >= rateLimitConfig.maxRequests) {
    res.status(429).json({ error: rateLimitConfig.message });
    return;
  }

  recentRequests.push(now);
  requestLog.set(clientIP, recentRequests);

  if (rateLimitConfig.standardHeaders) {
    res.setHeader('RateLimit-Limit', rateLimitConfig.maxRequests);
    res.setHeader('RateLimit-Remaining', rateLimitConfig.maxRequests - recentRequests.length);
    res.setHeader('RateLimit-Reset', Math.ceil((windowStart + rateLimitConfig.windowMs) / 1000));
  }

  next();
}

const requestLog = new Map<string, number[]>();

app.use(rateLimiter);
app.use('/api', router);
app.use(errorHandler);

// Health check
app.get('/health', (req, res) => {
  res.json({
    status: 'ok',
    uptime: process.uptime(),
    timestamp: new Date().toISOString(),
    version: process.env.APP_VERSION || '1.0.0',
  });
});

// Graceful shutdown
const server = app.listen(process.env.PORT || 3000, () => {
  console.log(`Server running on port ${process.env.PORT || 3000}`);
});

process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully...');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

export default app;
